final:
module RefModule(
  carry,
  sum,
  in3,
  in2,
  in1
  );input in1, in2, in3;
  output sum, carry;

  assign sum=in1^in2^in3;
  wire temp1_(in1&in2) | (in2&in3) = (in1&in2) | (in2&in3);
  wire temp2_(in1&in3) = (in1&in3);
  assign carry=temp1_(in1&in2) | (in2&in3) | temp2_(in1&in3);

endmodule
